package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.SP;
import java.io.Closeable;
import java.io.Flushable;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;
import org.mockito.invocation.InvocationOnMock;
import org.mockito.stubbing.Answer;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = spy(new CSVPrinter(out, format));
    }

    @Test
    void testPrintRecords_withMultipleRowsAndColumns() throws SQLException, IOException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(3);

        // We simulate two rows by controlling next() calls
        when(resultSet.next()).thenReturn(true, true, false);

        // We track the current row index to return different getObject values per row
        final int[] rowIndex = {0};

        // Answer to increment rowIndex on each next() call
        doAnswer(invocation -> {
            boolean hasNext = (boolean) invocation.callRealMethod();
            if (rowIndex[0] < 2 && hasNext) {
                rowIndex[0]++;
                return true;
            }
            return false;
        }).when(resultSet).next();

        // Instead of above, simpler to just increment rowIndex on next() calls using Answer:
        // But since we stubbed next() above, use a simpler approach:
        // Remove above doAnswer on next() and rely on thenReturn with side effect:
        // So let's rewrite:

        // Reset next stubbing:
        reset(resultSet);
        when(resultSet.getMetaData()).thenReturn(metaData);

        // We use an Answer for next() to increment rowIndex
        when(resultSet.next()).thenAnswer(new Answer<Boolean>() {
            private int count = 0;
            @Override
            public Boolean answer(InvocationOnMock invocation) {
                count++;
                return count <= 2;
            }
        });

        // getObject returns values depending on the current row (count of next calls)
        when(resultSet.getObject(anyInt())).thenAnswer(new Answer<Object>() {
            private int currentRow = 0;
            @Override
            public Object answer(InvocationOnMock invocation) {
                int columnIndex = invocation.getArgument(0);
                // We need to know current row, but ResultSet doesn't expose it.
                // We simulate by counting next() calls:
                // We can track next() calls by spying ResultSet or use a stateful variable.
                // Instead, track current row by incrementing on next() call:
                // We'll do this by a separate field outside of this Answer.

                // So we create a wrapper class to hold state:
                throw new UnsupportedOperationException("Should not be called directly");
            }
        });

        // To avoid complexity, implement row tracking outside mocks:
        // Implement a helper class for stateful mocking:

        class ResultSetMock {
            private int nextCount = 0;

            boolean next() {
                nextCount++;
                return nextCount <= 2;
            }

            Object getObject(int columnIndex) {
                if (nextCount == 1) {
                    switch (columnIndex) {
                        case 1: return "val11";
                        case 2: return "val12";
                        case 3: return "val13";
                        default: return null;
                    }
                } else if (nextCount == 2) {
                    switch (columnIndex) {
                        case 1: return "val21";
                        case 2: return "val22";
                        case 3: return "val23";
                        default: return null;
                    }
                }
                return null;
            }
        }
        final ResultSetMock rsMock = new ResultSetMock();

        // Reset mocks and stub with Answers that call rsMock methods
        reset(resultSet);
        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(3);

        when(resultSet.next()).thenAnswer(invocation -> rsMock.next());

        when(resultSet.getObject(anyInt())).thenAnswer(invocation -> {
            int col = invocation.getArgument(0);
            return rsMock.getObject(col);
        });

        printer.printRecords(resultSet);

        // Verify that print was called with each value in order
        InOrder inOrder = inOrder(printer);
        inOrder.verify(printer).print("val11");
        inOrder.verify(printer).print("val12");
        inOrder.verify(printer).print("val13");
        inOrder.verify(printer).println();
        inOrder.verify(printer).print("val21");
        inOrder.verify(printer).print("val22");
        inOrder.verify(printer).print("val23");
        inOrder.verify(printer).println();
    }

    @Test
    void testPrintRecords_withZeroColumns() throws SQLException, IOException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(0);
        when(resultSet.next()).thenReturn(true, false);

        printer.printRecords(resultSet);

        // No print calls expected, only println once
        verify(printer, times(1)).println();
        verify(printer, never()).print(any());
    }

    @Test
    void testPrintRecords_throwsSQLException() throws SQLException {
        ResultSet resultSet = mock(ResultSet.class);
        when(resultSet.getMetaData()).thenThrow(new SQLException("meta error"));

        try {
            printer.printRecords(resultSet);
        } catch (SQLException e) {
            // expected
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }

    @Test
    void testPrintRecords_throwsIOException() throws SQLException, IOException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(1);
        when(resultSet.next()).thenReturn(true, false);

        // Spy to throw IOException on print call
        CSVPrinter spyPrinter = spy(new CSVPrinter(out, format));
        doThrow(new IOException("io error")).when(spyPrinter).print(any());

        try {
            spyPrinter.printRecords(resultSet);
        } catch (IOException e) {
            // expected
        }
    }
}
